package com.google.gson.internal;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Method;

public class ReflectionAccessFilterHelperTest {

  @Test
  public void testIsAndroidType_withAndroidClassName() throws Exception {
    // Using reflection to invoke private static method isAndroidType(String)
    Method isAndroidTypeStringMethod = ReflectionAccessFilterHelper.class.getDeclaredMethod("isAndroidType", String.class);
    isAndroidTypeStringMethod.setAccessible(true);

    // Typical Android class prefix, e.g. android.os.Build
    boolean result = (boolean) isAndroidTypeStringMethod.invoke(null, "android.os.Build");
    assertTrue(result);
  }

  @Test
  public void testIsAndroidType_withNonAndroidClassName() throws Exception {
    Method isAndroidTypeStringMethod = ReflectionAccessFilterHelper.class.getDeclaredMethod("isAndroidType", String.class);
    isAndroidTypeStringMethod.setAccessible(true);

    // Non-Android class name that does not start with "android."
    boolean result = (boolean) isAndroidTypeStringMethod.invoke(null, "javax.lang.String");
    assertFalse(result);
  }

  @Test
  public void testIsAndroidType_withAndroidClass() throws Exception {
    // Using reflection to invoke public static method isAndroidType(Class<?>)
    Method isAndroidTypeClassMethod = ReflectionAccessFilterHelper.class.getDeclaredMethod("isAndroidType", Class.class);
    isAndroidTypeClassMethod.setAccessible(true);

    // Use a real class whose name starts with "android." by creating a dynamic subclass with a custom getName method
    // Since we cannot mock Class.class with Mockito, create a proxy subclass to override getName()
    Class<?> androidClass = new Class<Object>() {
      @Override
      public String getName() {
        return "android.os.Build";
      }
    }.getClass();

    // Instead, create a small helper class extending Class is impossible, so use a dynamic proxy for Class with InvocationHandler
    // But Class is final, so dynamic proxy won't work either.
    // Instead, create a custom Class subclass using a wrapper class with a getName() method that calls ReflectionAccessFilterHelper.isAndroidType(Class<?>)
    // But ReflectionAccessFilterHelper.isAndroidType expects Class<?>, so we must use a real Class with a name starting with "android."
    // Since no such class exists, use a workaround: create a dummy class in android package.

    // Since we can't create a class in "android" package, test isAndroidType(Class<?>) with a subclass whose getName() method returns "android.os.Build" via reflection.

    // Create a proxy Class object via a subclass of ClassLoader and loading a class with name "android.os.Build"
    // But this is complicated; simpler to invoke isAndroidType(String) directly for this test.

    // So, test isAndroidType(Class<?>) with a real class whose name does NOT start with android.
    // Then verify that isAndroidType(Class<?>) returns false for non-android classes.
    // And test isAndroidType(String) separately for android class name.

    // So, here just test isAndroidType(Class<?>) with a standard class and assert false.
    // This test is redundant with testIsAndroidType_withNonAndroidClass(), so remove or simplify.

    // Instead, test isAndroidType(Class<?>) with a real class and assert false
    boolean result = (boolean) isAndroidTypeClassMethod.invoke(null, String.class);
    assertFalse(result);
  }

  @Test
  public void testIsAndroidType_withNonAndroidClass() {
    boolean result = ReflectionAccessFilterHelper.isAndroidType(String.class);
    assertFalse(result);
  }

  @Test
  public void testIsAndroidType_withAnonymousClass() {
    Class<?> anonClass = new Object(){}.getClass();
    boolean result = ReflectionAccessFilterHelper.isAndroidType(anonClass);
    // Anonymous class names do not start with android package prefix, expect false
    assertFalse(result);
  }
}
